import { Card, Typography, Button } from 'antd';
import React, { useState } from 'react';
import { JournalManiaContainer } from './projects/journalMania';
import { WebsiteRedesignContainer } from './projects/websiteRedesign';

const { Text } = Typography;
const { Meta } = Card;

export const ProjectOverviewContainer = () => {
  const [currentView, setCurrentView] = useState('overview');

  const ProjectCard = ({ alt, src, title, description, onClick }) => (
    <Card
      hoverable
      style={{ width: 240, marginBottom: '20px'}}
      cover={
        <img
          draggable={false}
          alt={alt}
          src={src}
        />
      }
      onClick={onClick}
    >
      <Meta title={title} description={description} />
    </Card>
  )

  const mainRender = () => {
    switch (currentView) {
    case 'journalMania':
      return <JournalManiaContainer onBack={() => setCurrentView('overview')} />;
    case 'websiteRedesign':
      return <WebsiteRedesignContainer onBack={() => setCurrentView('overview')} />;
    case 'test3':
      return (
        <div>
          <Button onClick={() => setCurrentView('overview')}>Back to Overview</Button>
          <div>Test3 content</div>
        </div>
      );
    default:
      return (
        <div>
          <Text>Here you can get an overview of my projects.</Text>
          <div className='ProjectGrid'>
            <ProjectCard alt="Project 1" src="https://os.alipayobjects.com/rmsportal/QBnOOoLaAfKPirc.png" title="Journal Mania" description="Description for project one" onClick={() => setCurrentView('journalMania')} />
            <ProjectCard alt="Project 2" src="https://os.alipayobjects.com/rmsportal/QBnOOoLaAfKPirc.png" title="Website Redesign" description="Description for project two" onClick={() => setCurrentView('websiteRedesign')} />
            <ProjectCard alt="Project 3" src="https://os.alipayobjects.com/rmsportal/QBnOOoLaAfKPirc.png" title="The basic case study" description="Description for project three" onClick={() => setCurrentView('test3')} />
          </div>
        </div>
      );
  }
}

  return (
    <div>
      {mainRender()}
                  <iframe 
                title="Journal Mania Figma Prototype"
            style={{ 
                border: '1px solid rgb(255, 255, 255)', 
                width: '450px', 
                height: '800px',
                display: currentView === 'journalMania' ? 'block' : 'none'
            }} 
            src="https://embed.figma.com/proto/hDM9h4AqW79ZhFxiW7rw4C/Journal-Mania?node-id=19-160&scaling=scale-down&content-scaling=fixed&page-id=4%3A2&starting-point-node-id=19%3A160&embed-host=share"
            allowfullscreen
        >
        </iframe>
                <iframe 
            title="Website Redesign Figma Prototype"
            style={{ 
                border: '1px solid rgb(255, 255, 255)', 
                width: '800px', 
                height: '450px',
                display: currentView === 'websiteRedesign' ? 'block' : 'none'
            }}
            src="https://embed.figma.com/proto/zQ2jjowNahrh5KpJA60l36/otto.de-Redesign?node-id=17-2&p=f&scaling=scale-down&content-scaling=fixed&page-id=3%3A3&embed-host=share" 
            allowfullscreen
        >
        </iframe>
    </div>
  );
}
